/**
 * Look up a per-paint hex value from RedGrimm data
 * @param {string} range
 * @param {string} name
 * @returns {string | undefined}
 */
export function lookupHex(range, name) {
  const rangeData = HEX_LOOKUP[range];
  if (!rangeData) return undefined;
  const norm = name.toLowerCase().replace(/[^a-z0-9]/g, "");
  if (rangeData[norm]) return rangeData[norm];
  // Try without parenthetical code e.g. "Dead White (001)" -> "deadwhite"
  const noCode = name.replace(/\s*\([^)]*\)\s*$/, "").toLowerCase().replace(/[^a-z0-9]/g, "");
  return rangeData[noCode];
}
